// Gerar mensagens personalizadas para follow-up 3 dias
const leads = $input.all().map(i => i.json);

if (!leads || leads.length === 0 || !leads[0].id) {
  return [];
}

const mensagens = leads.map(lead => {
  const nome = lead.nome || 'amigo(a)';
  const primeiroNome = nome.split(' ')[0];
  const interesses = lead.interesses || 'desenvolvimento de site';

  // Variações de mensagem para 3 dias
  const templates = [
    `Oi ${primeiroNome}! 😊 Tudo bem? Sou da Buildesign e estava lembrando da nossa conversa sobre ${interesses}. Surgiu alguma dúvida? Estou por aqui para ajudar!`,
    `Olá ${primeiroNome}! Passando para saber se conseguiu pensar sobre o projeto que conversamos. Temos uma agenda aberta essa semana para uma call rápida, caso queira avançar! 🚀`,
    `Oi ${primeiroNome}! 👋 Vi que conversamos há uns dias sobre ${interesses}. Tem novidades sobre o projeto? Fico à disposição para tirar qualquer dúvida!`
  ];

  const randomIndex = Math.floor(Math.random() * templates.length);

  return {
    json: {
      leadId: lead.id,
      whatsapp: lead.whatsapp,
      nome: lead.nome,
      mensagem: templates[randomIndex],
      tipoFollowup: '3dias'
    }
  };
});

return mensagens;

// Gerar mensagens apelativas para follow-up 5 dias
