  return [];
}

const mensagens = leads.map(lead => {
  const nome = lead.nome || 'amigo(a)';
  const primeiroNome = nome.split(' ')[0];
  const interesses = lead.interesses || 'seu projeto digital';

  // Mensagens mais apelativas para 5 dias
  const templates = [
    `${primeiroNome}, tudo bem? 😊 Olha, essa semana estamos com condições especiais para novos projetos de sites. Se ainda estiver pensando em investir na presença digital do seu negócio, posso preparar uma proposta personalizada com um desconto exclusivo. Posso te mostrar?`,
    `Oi ${primeiroNome}! 🔥 Notícia boa: liberamos vagas limitadas com desconto para projetos iniciados esse mês. Lembrei da nossa conversa sobre ${interesses} e pensei em você. Que tal agendarmos 15 minutinhos para eu te apresentar uma proposta especial?`,
    `${primeiroNome}, passando para avisar que estamos com a agenda abrindo para novos projetos este mês. 📅 Como sei que você tem interesse em ${interesses}, queria te oferecer prioridade na fila + uma condição especial. Topa conversar rapidinho?`
  ];

  const randomIndex = Math.floor(Math.random() * templates.length);

  return {
    json: {
      leadId: lead.id,
      whatsapp: lead.whatsapp,
      nome: lead.nome,
      mensagem: templates[randomIndex],
      tipoFollowup: '5dias'
    }
  };
});

return mensagens;
